  1→import { getIssueTypeFromEvaluatorName } from "@shared/evaluation/evaluator-types";
  2→import type {
  3→	ILinkedDocSummary,
  4→	IProjectContext,
  5→	ISkill,
  6→	ITechnicalInventory,
  7→} from "@shared/types/evaluation";
  8→import { readFile } from "fs/promises";
  9→import { dirname, resolve } from "path";
 10→import { fileURLToPath } from "url";
 11→
 12→// Try to import embedded prompts (available in single binary mode)
 13→let embeddedSharedPrompts: Record<string, string> | null = null;
 14→try {
 15→	const embedded = await import("../../embedded/prompts-assets");
 16→	embeddedSharedPrompts = embedded.sharedPrompts;
 17→} catch {
 18→	// Not in embedded mode, will use file-based prompts
 19→}
 20→
 21→// Get directory paths for templates (file-based fallback)
 22→const __dirname = dirname(fileURLToPath(import.meta.url));
 23→const SHARED_TEMPLATES_DIR = resolve(__dirname, "../../../prompts/shared");
 24→
 25→/**
 26→ * Category-specific agent perspective descriptions
 27→ */
 28→const AGENT_PERSPECTIVES: Record<string, string> = {
 29→	"Content Quality & Focus":
 30→		"Agents need deterministic, executable instructions",
 31→	"Structure & Organization": "Agents parse structured text better than prose",
 32→	"Command Clarity": "Agents need unambiguous, executable commands",
 33→	"Testing Guidance": "Agents need to know how to verify their changes",
 34→	"Code Style Clarity":
 35→		"Agents need explicit rules to generate consistent code",
 36→	"Language Clarity":
 37→		"Agents need clear, unambiguous language without vague references",
 38→	"Workflow Integration": "Agents need to know how to integrate their changes",
 39→	"Project Structure": "Agents need to understand where to create/modify files",
 40→	"Security Awareness": "Agents need to know about security-sensitive areas",
 41→	"Completeness & Balance":
 42→		"Agents need sufficient but not overwhelming information",
 43→	"Subdirectory Coverage":
 44→		"Agents benefit from focused, context-specific guidance per component",
 45→	"Context Gaps & Documentation Opportunities":
 46→		"Agents benefit from explicit documentation of frameworks, patterns, and conventions",
 47→};
 48→
 49→/**
 50→ * Message shown when no context file (AGENTS.md, CLAUDE.md, or copilot-instructions.md) exists in the repository.
 51→ * Used by evaluators that support running without an existing file.
 52→ */
 53→const NO_FILE_MESSAGE = `## No Context File Found
 54→
 55→This repository does not have an AGENTS.md, CLAUDE.md, or copilot-instructions.md file. Focus on suggesting what documentation should be created based on the codebase analysis.
 56→
 57→Use location {"file": "AGENTS.md", "start": 0, "end": 0} for all issues since the file does not exist yet.`;
 58→
 59→/**
 60→ * Brief JSON-only reminder appended at the very end of every assembled prompt.
 61→ * Leverages recency bias so the model sees this constraint last, right before generating.
 62→ */
 63→const JSON_OUTPUT_REMINDER = `\n\n---\n\nREMINDER: Your ENTIRE response must be ONLY a valid JSON array. Start with \`[\` and end with \`]\`. No text before or after. No markdown. No explanations. Just the JSON array.`;
 64→
 65→/**
 66→ * Check if content is empty or effectively empty.
 67→ */
 68→export function isEmptyContent(content: string | undefined | null): boolean {
 69→	return !content || content.trim().length === 0;
 70→}
 71→
 72→/**
 73→ * Load and process the output format template with category-specific replacements
 74→ */
 75→async function loadOutputFormatTemplate(
 76→	category: string,
 77→	evaluatorName: string,
 78→): Promise<string> {
 79→	let template: string;
 80→
 81→	// Determine the issue type and template name
 82→	const issueType = getIssueTypeFromEvaluatorName(evaluatorName);
 83→	const templateName =
 84→		issueType === "suggestion"
 85→			? "output-format-suggestion"
 86→			: "output-format-error";
 87→
 88→	// Try embedded prompts first (single binary mode)
 89→	if (embeddedSharedPrompts && embeddedSharedPrompts[templateName]) {
 90→		template = embeddedSharedPrompts[templateName];
 91→	} else {
 92→		// Fall back to file-based prompts
 93→		const templatePath = resolve(SHARED_TEMPLATES_DIR, `${templateName}.md`);
 94→		try {
 95→			template = await readFile(templatePath, "utf-8");
 96→		} catch (_error) {
 97→			// If template not found, default to error template with warning
 98→			console.warn(
 99→				`Template ${templateName}.md not found, falling back to output-format-error.md`,
100→			);
101→			const fallbackPath = resolve(
102→				SHARED_TEMPLATES_DIR,
103→				"output-format-error.md",
104→			);
105→			template = await readFile(fallbackPath, "utf-8");
106→		}
107→	}
108→
109→	const agentPerspective =
110→		AGENT_PERSPECTIVES[category] || "Agents need clear, specific guidance";
111→
112→	return template
113→		.replace(/\{\{CATEGORY\}\}/g, category)
114→		.replace(/\{\{AGENT_PERSPECTIVE\}\}/g, agentPerspective);
115→}
116→
117→/**
118→ * Extract category from evaluator prompt title
119→ */
120→function extractCategory(evaluatorPrompt: string): string {
121→	// Look for pattern like "# Category Name Evaluator"
122→	const match = evaluatorPrompt.match(/^#\s+(.+?)\s+Evaluator/m);
123→	if (match && match[1]) {
124→		return match[1];
125→	}
126→	return "Unknown Category";
127→}
128→
129→/**
130→ * File context for multi-file evaluation
131→ */
132→export interface FileContext {
133→	filePath: string;
134→	relativePath: string;
135→	content: string;
136→}
137→
138→/**
139→ * Add line numbers to content for accurate location tracking
140→ * Format: "   1 | content line here"
141→ */
142→function addLineNumbers(content: string): string {
143→	const lines = content.split("\n");
144→	const maxLineNumWidth = String(lines.length).length;
145→	return lines
146→		.map((line, index) => {
147→			const lineNum = String(index + 1).padStart(maxLineNumWidth, " ");
148→			return `${lineNum} | ${line}`;
149→		})
150→		.join("\n");
151→}
152→
153→/**
154→ * Add line numbers with periodic file reminders to reduce cognitive load in multi-file contexts
155→ * Format: "   1 | content line here"
156→ * Adds reminder comments every 50 lines: "--- Still in file: path/to/file ---"
157→ */
158→function addLineNumbersWithReminders(
159→	content: string,
160→	filePath: string,
161→): string {
162→	const lines = content.split("\n");
163→	const maxLineNumWidth = String(lines.length).length;
164→	const reminderInterval = 50;
165→
166→	const result: string[] = [];
167→
168→	for (let index = 0; index < lines.length; index++) {
169→		const line = lines[index];
170→		const lineNum = String(index + 1).padStart(maxLineNumWidth, " ");
171→
172→		// Add reminder every 50 lines (but not at line 1)
173→		if (index > 0 && index % reminderInterval === 0) {
174→			result.push(`\n--- Still in file: ${filePath} ---\n`);
175→		}
176→
177→		result.push(`${lineNum} | ${line}`);
178→	}
179→
180→	return result.join("\n");
181→}
182→
183→/**
184→ * Format a file block with prominent separators and periodic reminders
185→ * This makes file boundaries unmistakable and reduces LLM confusion in multi-file contexts
186→ */
187→function formatFileBlockWithSeparators(
188→	file: FileContext,
189→	index: number,
190→): string {
191→	const separator = "=".repeat(80);
192→	const fileHeader = `FILE ${index + 1}: ${file.relativePath}`;
193→	const fileFooter = `END OF FILE ${index + 1}: ${file.relativePath}`;
194→
195→	if (isEmptyContent(file.content)) {
196→		return `${separator}\n${fileHeader}\n${separator}\n\n*File does not exist or is empty*\n\n${separator}\n${fileFooter}\n${separator}`;
197→	}
198→
199→	// Add line numbers with periodic reminders
200→	const numberedContent = addLineNumbersWithReminders(
201→		file.content,
202→		file.relativePath,
203→	);
204→
205→	return `${separator}\n${fileHeader}\n${separator}\n\n${numberedContent}\n\n${separator}\n${fileFooter}\n${separator}`;
206→}
207→
208→/**
209→ * Build the key folders section if available
210→ */
211→function buildKeyFoldersSection(
212→	keyFolders?: IProjectContext["keyFolders"],
213→): string {
214→	if (!keyFolders || keyFolders.length === 0) {
215→		return "";
216→	}
217→
218→	const folderLines = keyFolders
219→		.map((f) => `- ${f.path} - ${f.description}`)
220→		.join("\n");
221→
222→	return `### Key Folders
223→
224→${folderLines}
225→
226→`;
227→}
228→
229→/**
230→ * Build the context files section if available.
231→ * Lists all AGENTS.md, CLAUDE.md, and copilot-instructions.md files found in the repository.
232→ */
233→function buildAgentsFilesSection(agentsFilePaths?: string[]): string {
234→	if (!agentsFilePaths || agentsFilePaths.length === 0) {
235→		return "";
236→	}
237→
238→	const fileLines = agentsFilePaths.map((f) => `- ${f}`).join("\n");
239→
240→	return `### Context Files (AGENTS.md / CLAUDE.md / Rules / Github Copilot Instructions)
241→
242→${fileLines}
243→
244→`;
245→}
246→
247→/**
248→ * Build the Agent Skills section if available.
249→ * Lists all skills discovered from SKILL.md files in the repository.
250→ * Uses AI-generated summary when available, falls back to frontmatter description.
251→ */
252→function buildSkillsSection(skills: ISkill[]): string {
253→	if (!skills || skills.length === 0) {
254→		return "";
255→	}
256→
257→	const skillLines = skills
258→		.map((s) => {
259→			// Prefer AI-generated summary, fall back to frontmatter description
260→			const desc = s.summary || s.description;
261→			return `- **${s.name}** (${s.directory}/SKILL.md): ${desc}`;
262→		})
263→		.join("\n");
264→
265→	return `### Agent Skills in Repository
266→
267→The following ${skills.length} skill(s) are available:
268→
269→${skillLines}
270→
271→These skills provide specialized capabilities that may already address certain context gaps.
272→
273→`;
274→}
275→
276→/**
277→ * Build the linked documentation section if available.
278→ * Lists AI-generated summaries of documentation files linked from AGENTS.md.
279→ */
280→function buildLinkedDocsSection(linkedDocs?: ILinkedDocSummary[]): string {
281→	if (!linkedDocs || linkedDocs.length === 0) {
282→		return "";
283→	}
284→
285→	const docLines = linkedDocs
286→		.map((d) => `- **${d.path}**: ${d.summary}`)
287→		.join("\n");
288→
289→	return `### Referenced Documentation
290→
291→The AGENTS.md file references the following documentation:
292→
293→${docLines}
294→
295→`;
296→}
297→
298→/**
299→ * Build the technical inventory section if available.
300→ * Formats pre-computed codebase data so evaluators can reference it
301→ * instead of running redundant scanning commands.
302→ */
303→export function buildTechnicalInventorySection(
304→	inventory?: ITechnicalInventory,
305→): string {
306→	if (!inventory) {
307→		return "";
308→	}
309→
310→	const lines: string[] = ["### Technical Inventory (Pre-computed)", ""];
311→
312→	if (inventory.dependencies && inventory.dependencies.length > 0) {
313→		lines.push(`**Dependencies:** ${inventory.dependencies.join(", ")}`);
314→	}
315→
316→	if (inventory.devDependencies && inventory.devDependencies.length > 0) {
317→		lines.push(`**Dev Dependencies:** ${inventory.devDependencies.join(", ")}`);
318→	}
319→
320→	if (inventory.scripts && Object.keys(inventory.scripts).length > 0) {
321→		lines.push(`**Scripts:** ${Object.keys(inventory.scripts).join(", ")}`);
322→	}
323→
324→	if (inventory.dockerServices && inventory.dockerServices.length > 0) {
325→		lines.push(`**Docker Services:** ${inventory.dockerServices.join(", ")}`);
326→	}
327→
328→	if (inventory.configFiles && inventory.configFiles.length > 0) {
329→		lines.push(`**Config Files:** ${inventory.configFiles.join(", ")}`);
330→	}
331→
332→	if (
333→		inventory.fileCountsByExtension &&
334→		Object.keys(inventory.fileCountsByExtension).length > 0
335→	) {
336→		const counts = Object.entries(inventory.fileCountsByExtension)
337→			.sort(([, a], [, b]) => b - a)
338→			.map(([ext, count]) => `${ext} (${count})`)
339→			.join(", ");
340→		lines.push(`**File Counts:** ${counts}`);
341→	}
342→
343→	if (inventory.envVarNames && inventory.envVarNames.length > 0) {
344→		lines.push(`**Env Variables:** ${inventory.envVarNames.join(", ")}`);
345→	}
346→
347→	// Database patterns
348→	const dbParts: string[] = [];
349→	if (inventory.migrationFileCount)
350→		dbParts.push(`${inventory.migrationFileCount} migration files`);
351→	if (inventory.ormRelationshipCount)
352→		dbParts.push(`${inventory.ormRelationshipCount} ORM relationships`);
353→	if (inventory.seedFileCount)
354→		dbParts.push(`${inventory.seedFileCount} seed/factory files`);
355→	if (inventory.repositoryFileCount)
356→		dbParts.push(`${inventory.repositoryFileCount} repository files`);
357→	if (dbParts.length > 0) {
358→		lines.push(`**Database Patterns:** ${dbParts.join(", ")}`);
359→	}
360→
361→	// Testing patterns
362→	const testParts: string[] = [];
363→	if (inventory.mockUsageCount)
364→		testParts.push(`${inventory.mockUsageCount} mock usages`);
365→	if (inventory.testOrganization)
366→		testParts.push(`${inventory.testOrganization} test organization`);
367→	if (inventory.fixtureDirectories && inventory.fixtureDirectories.length > 0)
368→		testParts.push(
369→			`${inventory.fixtureDirectories.length} fixture dir(s): ${inventory.fixtureDirectories.join(", ")}`,
370→		);
371→	if (inventory.testUtilityFiles && inventory.testUtilityFiles.length > 0)
372→		testParts.push(
373→			`${inventory.testUtilityFiles.length} test util(s): ${inventory.testUtilityFiles.join(", ")}`,
374→		);
375→	if (testParts.length > 0) {
376→		lines.push(`**Testing Patterns:** ${testParts.join(", ")}`);
377→	}
378→
379→	// Architecture layers
380→	if (
381→		inventory.detectedDirectoryLayers &&
382→		inventory.detectedDirectoryLayers.length > 0
383→	) {
384→		lines.push(
385→			`**Architecture Layers:** ${inventory.detectedDirectoryLayers.join(", ")}`,
386→		);
387→	}
388→
389→	// Gitignore entries
390→	if (inventory.gitignoreEntries && inventory.gitignoreEntries.length > 0) {
391→		lines.push(
392→			`**Gitignore Entries:** ${inventory.gitignoreEntries.join(", ")}`,
393→		);
394→	}
395→
396→	// Only return if we have at least one data line beyond the header
397→	if (lines.length <= 2) {
398→		return "";
399→	}
400→
401→	lines.push("");
402→	return `${lines.join("\n")}\n`;
403→}
404→
405→/**
406→ * Build the project context section if available
407→ */
408→function buildProjectContextSection(projectContext?: string): string {
409→	if (!projectContext) {
410→		return "";
411→	}
412→
413→	return `## Project Context
414→
415→The following context was automatically identified from the codebase:
416→
417→${projectContext}
418→
419→---
420→
421→`;
422→}
423→
424→/**
425→ * Build the enhanced project context string from IProjectContext
426→ * Includes key folders and AGENTS.md file paths
427→ */
428→export function buildEnhancedProjectContext(context: IProjectContext): string {
429→	const parts: string[] = [];
430→
431→	// Add CLOC summary if available
432→	if (
433→		context.clocSummary &&
434→		context.clocSummary !==
435→			"CLOC analysis not available (tool not installed or timed out)"
436→	) {
437→		parts.push(context.clocSummary);
438→		parts.push("");
439→	}
440→
441→	// Add raw context (Languages, Frameworks, Architecture, Patterns)
442→	if (context.raw) {
443→		parts.push(context.raw.trim());
444→	}
445→
446→	// Add key folders section
447→	const keyFoldersSection = buildKeyFoldersSection(context.keyFolders);
448→	if (keyFoldersSection) {
449→		parts.push("");
450→		parts.push(keyFoldersSection.trim());
451→	}
452→
453→	// Add AGENTS.md files section
454→	const agentsFilesSection = buildAgentsFilesSection(context.agentsFilePaths);
455→	if (agentsFilesSection) {
456→		parts.push("");
457→		parts.push(agentsFilesSection.trim());
458→	}
459→
460→	// Add Agent Skills section
461→	const skillsSection = context.skills
462→		? buildSkillsSection(context.skills)
463→		: "";
464→	if (skillsSection) {
465→		parts.push("");
466→		parts.push(skillsSection.trim());
467→	}
468→
