 136→/**
 137→ * Run evaluators with concurrency limit to avoid overwhelming the system
 138→ */
 139→async function runWithConcurrencyLimit<T, R>(
 140→	items: T[],
 141→	limit: number,
 142→	fn: (item: T, index: number) => Promise<R>,
 143→): Promise<R[]> {
 144→	const results: R[] = new Array(items.length); // Pre-allocate array
 145→	let activeCount = 0;
 146→	let currentIndex = 0;
 147→
 148→	return new Promise((resolve) => {
 149→		const runNext = () => {
 150→			if (currentIndex >= items.length && activeCount === 0) {
 151→				resolve(results);
 152→				return;
 153→			}
 154→
 155→			while (activeCount < limit && currentIndex < items.length) {
 156→				const index = currentIndex++;
 157→				const item = items[index];
 158→
 159→				// Validate item exists
 160→				if (item === undefined) {
 161→					runnerLogger.error(`Item at index ${index} is undefined, skipping`);
 162→					results[index] = new Error("Item undefined") as R;
 163→					continue;
 164→				}
 165→
 166→				activeCount++;
 167→
 168→				fn(item, index)
 169→					.then((result) => {
 170→						results[index] = result;
 171→					})
 172→					.catch((error) => {
 173→						runnerLogger.error(`Task ${index} failed:`, error);
 174→						results[index] = error;
 175→					})
 176→					.finally(() => {
 177→						activeCount--;
 178→						runNext();
 179→					});
 180→			}
 181→		};
 182→
 183→		runNext();
 184→	});
 185→}
