 187→/**
 188→ * Run all evaluators against a single context file (AGENTS.md or CLAUDE.md) with controlled concurrency
 189→ */
 190→export async function runAllEvaluators(
 191→	agentsFilePath: string,
 192→	options: {
 193→		verbose?: boolean;
 194→		debug?: boolean;
 195→		debugDir?: string;
 196→		concurrency?: number;
 197→		evaluators?: number;
 198→		baseDir?: string;
 199→		projectContext?: string;
 200→		onProgress?: (evaluator: string, index: number, total: number) => void;
 201→		/** Callback for retry events */
 202→		onRetry?: (
 203→			evaluator: string,
 204→			attempt: number,
 205→			maxRetries: number,
 206→			error: string,
 207→		) => void;
 208→		/** Callback for timeout events */
 209→		onTimeout?: (
 210→			evaluator: string,
 211→			elapsedMs: number,
 212→			timeoutMs: number,
 213→		) => void;
 214→		/** When true, skip evaluators that require existing file content */
 215→		noFileMode?: boolean;
 216→		/** AI provider to use (defaults to claude) */
 217→		provider?: IAIProvider;
 218→		/** Filter evaluators by type */
 219→		evaluatorFilter?: EvaluatorFilter;
 220→		/** Specific evaluator IDs to run (overrides evaluatorFilter when set) */
 221→		selectedEvaluators?: string[];
 222→		/** Timeout per evaluator in milliseconds */
 223→		timeout?: number;
 224→	} = {},
 225→): Promise<EvaluatorResult[]> {
 226→	const {
 227→		verbose = false,
 228→		debug = false,
 229→		debugDir,
 230→		concurrency = 3,
 231→		evaluators = 100,
 232→		baseDir,
 233→		projectContext,
 234→		onProgress,
 235→		onRetry,
 236→		onTimeout,
 237→		noFileMode = false,
 238→		provider = getProvider(),
 239→		evaluatorFilter = "all",
 240→		selectedEvaluators,
 241→		timeout = DEFAULT_TIMEOUT_MS,
 242→	} = options;
 243→
 244→	// Apply filter first, then limit by count
 245→	const allEvaluatorFiles = EVALUATOR_FILES;
 246→	const filteredFiles =
 247→		selectedEvaluators && selectedEvaluators.length > 0
 248→			? filterEvaluatorsByIds(allEvaluatorFiles, selectedEvaluators)
 249→			: filterEvaluatorsByType(allEvaluatorFiles, evaluatorFilter);
 250→	const selectedFiles = filteredFiles.slice(
 251→		0,
 252→		Math.min(evaluators, filteredFiles.length),
 253→	);
 254→	const evaluatorPaths = selectedFiles.map((file) =>
 255→		resolve(EVALUATORS_DIR, file),
 256→	);
 257→
 258→	if (verbose) {
 259→		runnerLogger.log(
 260→			`Running ${evaluatorPaths.length} evaluators (filter: ${evaluatorFilter}, limit: ${evaluators}, concurrency: ${concurrency})`,
 261→		);
 262→	}
 263→
 264→	// Run evaluators with concurrency limit
 265→	const results = await runWithConcurrencyLimit(
 266→		evaluatorPaths,
 267→		concurrency,
 268→		async (evaluatorPath, i) => {
 269→			const evaluatorFilename = selectedFiles[i]!;
 270→			const evaluatorName = evaluatorFilename.replace(".md", "");
 271→
 272→			if (onProgress) {
 273→				onProgress(evaluatorName, i + 1, evaluatorPaths.length);
 274→			}
 275→
 276→			// Check if evaluator should be skipped in no-file mode
 277→			if (noFileMode && !shouldExecuteIfNoFile(evaluatorFilename)) {
 278→				if (verbose) {
 279→					runnerLogger.log(
 280→						`Skipping ${evaluatorName} - requires existing file content`,
 281→					);
 282→				}
 283→				return {
 284→					evaluator: evaluatorName,
 285→					issues: [],
 286→					skipped: true,
 287→					skipReason:
 288→						"No context file exists and this evaluator requires existing content to evaluate",
 289→				};
 290→			}
 291→
 292→			// Check if this evaluator requires file filtering
 293→			if (hasFileFiltering(evaluatorFilename)) {
 294→				const reason = getFilteringReason(evaluatorFilename);
 295→				const filterBaseDir = baseDir || dirname(agentsFilePath);
 296→
 297→				// Apply filtering to determine if this file should be evaluated
 298→				const filteredFiles = filterFilesForEvaluator(
 299→					evaluatorFilename,
 300→					[agentsFilePath],
 301→					filterBaseDir,
 302→				);
 303→
 304→				// If this file was filtered out, return empty result
 305→				if (filteredFiles.length === 0) {
 306→					if (verbose) {
 307→						runnerLogger.log(
 308→							`${evaluatorName} has file filtering enabled: ${reason}`,
 309→						);
 310→						runnerLogger.log(
 311→							`Skipping evaluation for this file (not root-level)`,
 312→						);
 313→					}
 314→					return {
 315→						evaluator: evaluatorName,
 316→						issues: [],
 317→					};
 318→				}
 319→
 320→				if (verbose) {
 321→					runnerLogger.log(
 322→						`${evaluatorName} has file filtering enabled: ${reason}`,
 323→					);
 324→					runnerLogger.log(`File passed filtering, proceeding with evaluation`);
 325→				}
 326→			}
 327→
 328→			try {
 329→				if (verbose) {
 330→					runnerLogger.log(`\n========================================`);
 331→					runnerLogger.log(
 332→						`Starting evaluator ${i + 1}/${evaluatorPaths.length}: ${evaluatorName}`,
 333→					);
 334→					runnerLogger.log(`========================================`);
 335→				}
 336→
 337→				// Read evaluator and AGENTS.md content
 338→				let evaluatorPrompt: string;
 339→				let agentsContent: string;
 340→
 341→				try {
 342→					evaluatorPrompt = await loadEvaluatorPrompt(evaluatorPath);
 343→					agentsContent = noFileMode
 344→						? ""
 345→						: await readFile(agentsFilePath, "utf-8");
 346→				} catch (error) {
 347→					const errorMessage =
 348→						error instanceof Error ? error.message : String(error);
 349→					runnerLogger.error(
 350→						`Failed to read files for ${evaluatorName}:`,
 351→						errorMessage,
 352→					);
 353→					return {
 354→						evaluator: evaluatorName,
 355→						issues: [],
 356→						error: `File read error: ${errorMessage}`,
 357→					};
 358→				}
 359→
 360→				if (verbose) {
 361→					runnerLogger.log(
 362→						`Read evaluator prompt (${evaluatorPrompt.length} chars)`,
 363→					);
 364→					runnerLogger.log(
 365→						`Read AGENTS.md content (${agentsContent.length} chars)`,
 366→					);
 367→				}
 368→
 369→				// Build prompt with project context
 370→				const fullPrompt = await buildSingleFilePrompt(
 371→					evaluatorPrompt,
 372→					agentsContent,
 373→					projectContext,
 374→					evaluatorName,
 375→				);
 376→
 377→				if (verbose) {
 378→					runnerLogger.log(`Built final prompt: ${fullPrompt.length} chars`);
 379→					runnerLogger.log(`Invoking ${provider.displayName}...`);
 380→				}
 381→
 382→				// Save prompt to debug directory if debug mode is enabled
 383→				if (debug && debugDir) {
 384→					try {
 385→						const promptFile = resolve(debugDir, `${evaluatorName}-prompt.md`);
 386→						await writeFile(promptFile, fullPrompt, "utf-8");
 387→						if (verbose) {
 388→							const debugLogger = createLogger("Debug");
 389→							debugLogger.log(`Saved prompt to: ${promptFile}`);
 390→						}
 391→					} catch (debugWriteError) {
 392→						const debugLogger = createLogger("Debug");
 393→						debugLogger.error(
 394→							`Failed to save debug prompt for ${evaluatorName}: ${debugWriteError}`,
 395→						);
 396→					}
 397→				}
 398→
 399→				// NEW: Always log runtime prompt to persistent debug folder (blocking write)
 400→				await logRuntimePrompt({
 401→					evaluatorName,
 402→					prompt: fullPrompt,
 403→					mode: "independent",
 404→					verbose,
 405→				});
 406→
 407→				// Log execution context before invoking AI agent
 408→				runnerLogger.log(
 409→					`[Agent] Executing evaluator: ${evaluatorName} (independent mode)`,
 410→				);
 411→				runnerLogger.log(
 412→					`[Agent] Working directory: ${baseDir || process.cwd()}`,
 413→				);
 414→
 415→				// Invoke provider with retry logic
 416→				const evaluatorStartTime = Date.now();
 417→				const response = await provider.invokeWithRetry(fullPrompt, {
 418→					verbose,
 419→					timeout, // Configurable timeout (default: 10 minutes)
 420→					cwd: baseDir, // Execute in the cloned repository directory
 421→					onRetry: onRetry
 422→						? (event) =>
 423→								onRetry(
 424→									evaluatorName,
 425→									event.attempt,
 426→									event.maxRetries,
 427→									event.error,
 428→								)
 429→						: undefined,
 430→					onTimeout: onTimeout
 431→						? (event) =>
 432→								onTimeout(evaluatorName, event.elapsedMs, event.timeoutMs)
 433→						: undefined,
 434→				});
 435→				const evaluatorDuration = (Date.now() - evaluatorStartTime) / 1000;
 436→
 437→				if (verbose) {
 438→					const evaluatorLogger = createLogger("Evaluator");
 439→					const resultPreview = response.result
 440→						? response.result.substring(0, 1000)
 441→						: "(empty)";
 442→					evaluatorLogger.log(
 443→						`Response type: ${typeof response.result}, length: ${response.result?.length ?? 0}`,
 444→					);
 445→					evaluatorLogger.log(
 446→						`Raw response (first 1000 chars):\n${resultPreview}...`,
 447→					);
 448→				}
 449→
 450→				// Save response to debug directory if debug mode is enabled
 451→				if (debug && debugDir) {
 452→					try {
 453→						const responseFile = resolve(
 454→							debugDir,
 455→							`${evaluatorName}-response.json`,
 456→						);
 457→						await writeFile(
 458→							responseFile,
 459→							JSON.stringify(response, null, 2),
 460→							"utf-8",
 461→						);
 462→						if (verbose) {
 463→							const debugLogger = createLogger("Debug");
 464→							debugLogger.log(`Saved response to: ${responseFile}`);
 465→						}
 466→					} catch (debugWriteError) {
 467→						const debugLogger = createLogger("Debug");
 468→						debugLogger.error(
 469→							`Failed to save debug response for ${evaluatorName}: ${debugWriteError}`,
 470→						);
 471→					}
 472→				}
 473→
 474→				// Parse issues from response
 475→				if (verbose) {
 476→					runnerLogger.log(`Parsing response for issues...`);
 477→				}
 478→				const parseResult = parseEvaluatorResult(response.result, verbose);
 479→
 480→				// Add issueType to each issue based on evaluator
 481→				const issueType = getIssueTypeFromEvaluatorName(evaluatorFilename);
 482→				for (const issue of parseResult.issues) {
 483→					issue.issueType = issueType;
 484→				}
 485→
 486→				// Populate snippets from file content
 487→				populateSnippets(parseResult.issues, new Map(), agentsContent);
 488→
 489→				// Enhance parsing errors with evaluator context
 490→				const errors: StructuredError[] = parseResult.errors.map((e) => ({
 491→					...e,
 492→					evaluatorName: evaluatorName,
 493→					filePath: agentsFilePath,
 494→				}));
 495→
 496→				// Always log evaluator completion with timing
 497→				const evalLogger = createLogger(evaluatorName);
 498→				evalLogger.log(`✓ Completed in ${evaluatorDuration.toFixed(1)}s`);
 499→
 500→				if (verbose) {
 501→					runnerLogger.log(`✓ Found ${parseResult.issues.length} issues`);
 502→					if (errors.length > 0) {
 503→						runnerLogger.warn(`⚠️  ${errors.length} parsing error(s) occurred`);
 504→					}
 505→					if (response.usage) {
 506→						runnerLogger.log(formatTokenUsage(response.usage));
 507→						if (response.cost_usd) {
 508→							runnerLogger.log(`Cost: $${response.cost_usd.toFixed(4)}`);
 509→						}
 510→					}
 511→					if (response.duration_ms) {
 512→						runnerLogger.log(
 513→							`API processing time: ${(response.duration_ms / 1000).toFixed(1)}s`,
 514→						);
 515→					}
 516→				}
 517→
 518→				return {
 519→					evaluator: evaluatorName,
 520→					issues: parseResult.issues,
 521→					errors: errors.length > 0 ? errors : undefined,
 522→					usage: response.usage,
 523→					cost_usd: response.cost_usd,
 524→					duration_ms: response.duration_ms,
 525→					finalPrompt: fullPrompt,
 526→				};
 527→			} catch (error) {
 528→				const errorMessage =
 529→					error instanceof Error ? error.message : String(error);
 530→				const isTimeout =
 531→					errorMessage.includes("timeout") || errorMessage.includes("TIMEOUT");
 532→
 533→				// Log with appropriate symbol and timing info
 534→				const evalLogger = createLogger(evaluatorName);
 535→				if (isTimeout) {
 536→					evalLogger.log(`❌ TIMEOUT after ${(timeout / 1000).toFixed(1)}s`);
 537→				} else {
 538→					runnerLogger.error(`\n❌ Evaluator ${evaluatorName} FAILED`);
 539→					runnerLogger.error(`Error: ${errorMessage}\n`);
 540→				}
 541→				if (verbose && error instanceof Error && error.stack) {
 542→					runnerLogger.error(`Stack trace:\n${error.stack}`);
 543→				}
 544→
 545→				// Create structured error
 546→				const structuredError: StructuredError = {
 547→					message: errorMessage,
 548→					category: determineErrorCategory(error),
 549→					severity: "partial",
 550→					evaluatorName: evaluatorName,
 551→					filePath: agentsFilePath,
 552→					timestamp: new Date(),
 553→					retryable: false,
 554→					technicalDetails: error instanceof Error ? error.stack : undefined,
 555→				};
 556→
 557→				return {
 558→					evaluator: evaluatorName,
 559→					issues: [],
 560→					error: errorMessage,
 561→					errors: [structuredError],
 562→				};
 563→			}
 564→		},
 565→	);
 566→
 567→	return results;
 568→}
