 577→/**
 578→ * Count issues by severity
 579→ * Thresholds: High (8-10), Medium (6-7), Low (5)
 580→ * Note: Evaluator prompts instruct AI to not report issues with severity ≤4
 581→ */
 582→export function countBySeverity(issues: Issue[]): {
 583→	high: number;
 584→	medium: number;
 585→	low: number;
 586→} {
 587→	return {
 588→		high: issues.filter((i) => getIssueSeverity(i) >= 8).length,
 589→		medium: issues.filter(
 590→			(i) => getIssueSeverity(i) >= 6 && getIssueSeverity(i) < 8,
 591→		).length,
 592→		low: issues.filter((i) => getIssueSeverity(i) < 6).length,
 593→	};
 594→}
