 596→/**
 597→ * Create a summary of evaluation results for a file
 598→ */
 599→export function createFileResult(
 600→	filePath: string,
 601→	relativePath: string,
 602→	evaluations: EvaluatorResult[],
 603→): FileEvaluationResult {
 604→	const allIssues = aggregateIssues(evaluations);
 605→	const counts = countBySeverity(allIssues);
 606→
 607→	// Aggregate token usage and costs
 608→	let totalInputTokens = 0;
 609→	let totalOutputTokens = 0;
 610→	let totalCacheCreation = 0;
 611→	let totalCacheRead = 0;
 612→	let totalCost = 0;
 613→	let totalDuration = 0;
 614→
 615→	for (const evaluation of evaluations) {
 616→		if (evaluation.usage) {
 617→			totalInputTokens += evaluation.usage.input_tokens;
 618→			totalOutputTokens += evaluation.usage.output_tokens;
 619→			totalCacheCreation += evaluation.usage.cache_creation_input_tokens || 0;
 620→			totalCacheRead += evaluation.usage.cache_read_input_tokens || 0;
 621→		}
 622→		if (evaluation.cost_usd) {
 623→			totalCost += evaluation.cost_usd;
 624→		}
 625→		if (evaluation.duration_ms) {
 626→			totalDuration += evaluation.duration_ms;
 627→		}
 628→	}
 629→
 630→	return {
 631→		filePath,
 632→		relativePath,
 633→		evaluations,
 634→		totalIssues: allIssues.length,
 635→		highCount: counts.high,
 636→		mediumCount: counts.medium,
 637→		lowCount: counts.low,
 638→		totalUsage: {
 639→			input_tokens: totalInputTokens,
 640→			output_tokens: totalOutputTokens,
 641→			cache_creation_input_tokens: totalCacheCreation,
 642→			cache_read_input_tokens: totalCacheRead,
 643→		},
 644→		totalCost: totalCost > 0 ? totalCost : undefined,
 645→		totalDuration: totalDuration > 0 ? totalDuration : undefined,
 646→	};
 647→}
