 697→/**
 698→ * Build multi-file context from file paths
 699→ */
 700→export async function buildMultiFileContext(
 701→	filePaths: string[],
 702→	getRelativePath: (path: string) => string,
 703→): Promise<MultiFileContext> {
 704→	const files: FileContext[] = [];
 705→	let totalContent = "";
 706→	const timeout = 30000; // 30 second timeout
 707→
 708→	for (const filePath of filePaths) {
 709→		try {
 710→			const content = await Promise.race([
 711→				readFile(filePath, "utf-8"),
 712→				new Promise<never>((_, reject) =>
 713→					setTimeout(
 714→						() => reject(new Error(`File read timeout after ${timeout}ms`)),
 715→						timeout,
 716→					),
 717→				),
 718→			]);
 719→			const relativePath = getRelativePath(filePath);
 720→			files.push({ filePath, relativePath, content });
 721→			totalContent += content;
 722→		} catch (error) {
 723→			const errorMessage =
 724→				error instanceof Error ? error.message : String(error);
 725→			throw new Error(`Failed to read ${filePath}: ${errorMessage}`);
 726→		}
 727→	}
 728→
 729→	return {
 730→		files,
 731→		totalTokenEstimate: estimateTokens(totalContent),
 732→	};
 733→}
 734→
 735→/**
 736→ * Check if unified evaluation is viable given token limits
 737→ */
 738→export function canUseUnifiedMode(
 739→	context: MultiFileContext,
 740→	maxTokens: number = DEFAULT_MAX_UNIFIED_TOKENS,
 741→): { viable: boolean; reason?: string } {
 742→	if (context.totalTokenEstimate > maxTokens) {
 743→		return {
 744→			viable: false,
 745→			reason: `Combined file content (~${context.totalTokenEstimate} tokens) exceeds limit (${maxTokens} tokens)`,
 746→		};
 747→	}
 748→	return { viable: true };
 749→}
