 757→	options: {
 758→		verbose?: boolean;
 759→		debug?: boolean;
 760→		debugDir?: string;
 761→		concurrency?: number;
 762→		evaluators?: number;
 763→		maxTokens?: number;
 764→		baseDir?: string;
 765→		projectContext?: string;
 766→		onProgress?: (evaluator: string, index: number, total: number) => void;
 767→		/** Callback for retry events */
 768→		onRetry?: (
 769→			evaluator: string,
 770→			attempt: number,
 771→			maxRetries: number,
 772→			error: string,
 773→		) => void;
 774→		/** Callback for timeout events */
 775→		onTimeout?: (
 776→			evaluator: string,
 777→			elapsedMs: number,
 778→			timeoutMs: number,
 779→		) => void;
 780→		/** When true, skip evaluators that require existing file content */
 781→		noFileMode?: boolean;
 782→		/** AI provider to use (defaults to claude) */
 783→		provider?: IAIProvider;
 784→		/** Filter evaluators by type */
 785→		evaluatorFilter?: EvaluatorFilter;
 786→		/** Specific evaluator IDs to run (overrides evaluatorFilter when set) */
 787→		selectedEvaluators?: string[];
 788→		/** Timeout per evaluator in milliseconds */
 789→		timeout?: number;
 790→	} = {},
 791→): Promise<UnifiedEvaluationResult> {
 792→	const {
 793→		verbose = false,
 794→		debug = false,
 795→		debugDir,
 796→		concurrency = 3,
 797→		evaluators = 100,
 798→		maxTokens = DEFAULT_MAX_UNIFIED_TOKENS,
 799→		baseDir,
 800→		projectContext,
 801→		onProgress,
 802→		onRetry,
 803→		onTimeout,
 804→		noFileMode = false,
 805→		provider = getProvider(),
 806→		evaluatorFilter = "all",
 807→		selectedEvaluators,
 808→		timeout = DEFAULT_TIMEOUT_MS,
 809→	} = options;
 810→
 811→	// Build file context
 812→	const context = await buildMultiFileContext(filePaths, getRelativePath);
 813→
 814→	const unifiedLogger = createLogger("Unified");
 815→	if (verbose) {
 816→		unifiedLogger.log(`Building context for ${context.files.length} files`);
 817→		unifiedLogger.log(`Total estimated tokens: ${context.totalTokenEstimate}`);
 818→	}
 819→
 820→	// Check if unified mode is viable
 821→	const viability = canUseUnifiedMode(context, maxTokens);
 822→	if (!viability.viable) {
 823→		throw new Error(`Cannot use unified mode: ${viability.reason}`);
 824→	}
 825→
 826→	// Apply filter first, then limit by count
 827→	const allEvaluatorFiles = EVALUATOR_FILES;
 828→	const filteredFiles =
 829→		selectedEvaluators && selectedEvaluators.length > 0
 830→			? filterEvaluatorsByIds(allEvaluatorFiles, selectedEvaluators)
 831→			: filterEvaluatorsByType(allEvaluatorFiles, evaluatorFilter);
 832→	const selectedFiles = filteredFiles.slice(
 833→		0,
 834→		Math.min(evaluators, filteredFiles.length),
 835→	);
 836→	const evaluatorPaths = selectedFiles.map((file) =>
 837→		resolve(EVALUATORS_DIR, file),
 838→	);
 839→
 840→	if (verbose) {
 841→		unifiedLogger.log(
 842→			`Running ${evaluatorPaths.length} evaluators (filter: ${evaluatorFilter}, limit: ${evaluators}, concurrency: ${concurrency})`,
 843→		);
 844→	}
 845→
 846→	// Run evaluators with concurrency limit
 847→	const evaluatorResults: UnifiedEvaluatorResult[] =
 848→		await runWithConcurrencyLimit(
 849→			evaluatorPaths,
 850→			concurrency,
 851→			async (evaluatorPath, i) => {
 852→				const evaluatorFilename = selectedFiles[i]!;
 853→				const evaluatorName = evaluatorFilename.replace(".md", "");
 854→
 855→				if (onProgress) {
 856→					onProgress(evaluatorName, i + 1, evaluatorPaths.length);
 857→				}
 858→
 859→				// Check if evaluator should be skipped in no-file mode
 860→				if (noFileMode && !shouldExecuteIfNoFile(evaluatorFilename)) {
 861→					if (verbose) {
 862→						unifiedLogger.log(
 863→							`Skipping ${evaluatorName} - requires existing file content`,
 864→						);
 865→					}
 866→					// Initialize empty per-file issues for skipped evaluator
 867→					const perFileIssues: Record<string, Issue[]> = {};
 868→					for (const file of context.files) {
 869→						perFileIssues[file.relativePath] = [];
 870→					}
 871→					return {
 872→						evaluator: evaluatorName,
 873→						perFileIssues,
 874→						crossFileIssues: [],
 875→						skipped: true,
 876→						skipReason:
 877→							"No context file exists and this evaluator requires existing content to evaluate",
 878→					};
 879→				}
 880→
 881→				// Apply file filtering for this evaluator
 882→				const filterBaseDir =
 883→					filePaths.length > 0 && filePaths[0]
 884→						? dirname(filePaths[0])
 885→						: process.cwd();
 886→				const filteredPaths = filterFilesForEvaluator(
 887→					evaluatorFilename,
 888→					filePaths,
 889→					filterBaseDir,
 890→				);
 891→
 892→				// Log filtering if verbose
 893→				if (verbose && hasFileFiltering(evaluatorFilename)) {
 894→					const reason = getFilteringReason(evaluatorFilename);
 895→					unifiedLogger.log(
 896→						`${evaluatorName}: Filtering ${filePaths.length} → ${filteredPaths.length} files`,
 897→					);
 898→					unifiedLogger.log(`Reason: ${reason}`);
 899→					unifiedLogger.log(
 900→						`Files: ${filteredPaths.map((f) => getRelativePath(f)).join(", ")}`,
 901→					);
 902→				}
 903→
 904→				// Build filtered file context for this evaluator
 905→				const filteredContext = await buildMultiFileContext(
 906→					filteredPaths,
 907→					getRelativePath,
 908→				);
 909→
 910→				try {
 911→					// Read evaluator prompt
 912→					const evaluatorPrompt = await loadEvaluatorPrompt(evaluatorPath);
 913→
 914→					// Build multi-file prompt with project context
 915→					const fullPrompt = await buildMultiFilePrompt(
 916→						evaluatorPrompt,
 917→						filteredContext.files,
 918→						projectContext,
 919→						evaluatorName,
 920→					);
 921→					const tokenEstimate = estimateTokens(fullPrompt);
 922→
 923→					if (verbose) {
 924→						const evaluatorLogger = createLogger("Evaluator");
 925→						evaluatorLogger.log(
 926→							`Running multi-file evaluation: ${evaluatorPath}`,
 927→						);
 928→						evaluatorLogger.log(
 929→							`Files: ${filteredContext.files.map((f) => f.relativePath).join(", ")}`,
 930→						);
 931→						evaluatorLogger.log(
 932→							`Prompt length: ${fullPrompt.length} chars (~${tokenEstimate} tokens)`,
 933→						);
 934→					}
 935→
 936→					// Save prompt to debug directory if debug mode is enabled
 937→					if (debug && debugDir) {
 938→						try {
 939→							const promptFile = resolve(
 940→								debugDir,
 941→								`${evaluatorName}-unified-prompt.md`,
 942→							);
 943→							await writeFile(promptFile, fullPrompt, "utf-8");
 944→							if (verbose) {
 945→								const debugLogger = createLogger("Debug");
 946→								debugLogger.log(`Saved unified prompt to: ${promptFile}`);
 947→							}
 948→						} catch (debugWriteError) {
 949→							const debugLogger = createLogger("Debug");
 950→							debugLogger.error(
 951→								`Failed to save debug prompt for ${evaluatorName}: ${debugWriteError}`,
 952→							);
 953→						}
 954→					}
 955→
 956→					// NEW: Always log runtime prompt to persistent debug folder (blocking write)
 957→					await logRuntimePrompt({
 958→						evaluatorName,
 959→						prompt: fullPrompt,
 960→						mode: "unified",
 961→						verbose,
 962→					});
 963→
 964→					// Log execution context before invoking AI agent
 965→					runnerLogger.log(
 966→						`[Agent] Executing evaluator: ${evaluatorName} (unified mode)`,
 967→					);
 968→					runnerLogger.log(
 969→						`[Agent] Working directory: ${baseDir || process.cwd()}`,
 970→					);
 971→
 972→					// Invoke provider with retry logic
 973→					const evaluatorStartTime = Date.now();
 974→					const response = await provider.invokeWithRetry(fullPrompt, {
 975→						verbose,
 976→						timeout, // Configurable timeout (default: 10 minutes)
 977→						cwd: baseDir, // Execute in the cloned repository directory
 978→						onRetry: onRetry
 979→							? (event) =>
 980→									onRetry(
 981→										evaluatorName,
 982→										event.attempt,
 983→										event.maxRetries,
 984→										event.error,
 985→									)
 986→							: undefined,
 987→						onTimeout: onTimeout
 988→							? (event) =>
 989→									onTimeout(evaluatorName, event.elapsedMs, event.timeoutMs)
 990→							: undefined,
 991→					});
 992→					const evaluatorDuration = (Date.now() - evaluatorStartTime) / 1000;
 993→
 994→					if (verbose) {
 995→						unifiedLogger.log(`\n✓ Received response from provider`);
 996→						unifiedLogger.log(
 997→							`Response type: ${typeof response.result}, length: ${response.result?.length ?? 0}`,
 998→						);
 999→						const resultPreview = response.result
1000→							? response.result.substring(0, 500)
1001→							: "(empty)";
1002→						unifiedLogger.log(
1003→							`Response preview (first 500 chars):\n${resultPreview}...`,
1004→						);
1005→					}
1006→
1007→					// Save response to debug directory if debug mode is enabled
1008→					if (debug && debugDir) {
1009→						try {
1010→							const responseFile = resolve(
1011→								debugDir,
1012→								`${evaluatorName}-unified-response.json`,
1013→							);
1014→							await writeFile(
1015→								responseFile,
1016→								JSON.stringify(response, null, 2),
1017→								"utf-8",
1018→							);
1019→							if (verbose) {
1020→								const debugLogger = createLogger("Debug");
1021→								debugLogger.log(`Saved unified response to: ${responseFile}`);
1022→							}
1023→						} catch (debugWriteError) {
1024→							const debugLogger = createLogger("Debug");
1025→							debugLogger.error(
1026→								`Failed to save debug response for ${evaluatorName}: ${debugWriteError}`,
1027→							);
1028→						}
1029→					}
1030→
1031→					// Parse the JSON array from the result
1032→					const parseResult = parseEvaluatorResult(response.result, verbose);
1033→
1034→					// Add issueType to each issue based on evaluator
1035→					const issueType = getIssueTypeFromEvaluatorName(evaluatorFilename);
1036→					for (const issue of parseResult.issues) {
1037→						issue.issueType = issueType;
1038→					}
1039→
1040→					// Enhance parsing errors with evaluator context
1041→					const errors: StructuredError[] = parseResult.errors.map((e) => ({
1042→						...e,
1043→						evaluatorName: evaluatorName,
1044→					}));
1045→
1046→					const contentMap = new Map<string, string>();
1047→					const basenameMap = new Map<string, string[]>(); // Track basenames to detect duplicates
1048→
1049→					for (const file of filteredContext.files) {
1050→						contentMap.set(file.relativePath, file.content);
1051→
1052→						// Track basenames to detect duplicates
1053→						const filename = file.relativePath.split("/").pop();
1054→						if (filename) {
1055→							if (!basenameMap.has(filename)) {
1056→								basenameMap.set(filename, []);
1057→							}
1058→							basenameMap.get(filename)!.push(file.relativePath);
1059→						}
1060→					}
1061→
1062→					// Warn about duplicate basenames (informational)
1063→					if (verbose) {
1064→						for (const [basename, fullPaths] of basenameMap) {
1065→							if (fullPaths.length > 1) {
1066→								const hasRootLevel = fullPaths.some((p) => !p.includes("/"));
1067→								runnerLogger.warn(
1068→									`ℹ️  Info: Multiple files with basename "${basename}":`,
1069→								);
1070→								for (const path of fullPaths) {
1071→									const marker = !path.includes("/") ? " (default)" : "";
1072→									runnerLogger.warn(`    - ${path}${marker}`);
1073→								}
1074→								if (hasRootLevel) {
1075→									runnerLogger.warn(
1076→										`Basename-only references (e.g., "${basename}") will use root-level file`,
1077→									);
1078→								} else {
1079→									runnerLogger.warn(
1080→										`⚠️  No root-level file found - evaluators MUST use full relative paths`,
1081→									);
1082→								}
1083→							}
1084→						}
1085→					}
1086→
1087→					// Use first AGENTS.md or CLAUDE.md file content as fallback
1088→					const defaultContent = filteredContext.files.find(
1089→						(f) =>
1090→							f.relativePath.includes("AGENTS.md") ||
1091→							f.relativePath.includes("CLAUDE.md"),
1092→					)?.content;
1093→
1094→					// Populate snippets from file content
1095→					populateSnippets(parseResult.issues, contentMap, defaultContent);
1096→
1097→					// Also populate cross-file snippets
1098→					populateCrossFileSnippets(parseResult.issues, contentMap);
1099→
1100→					// Separate per-file and cross-file issues
1101→					const { perFileIssues, crossFileIssues } = separateIssuesByType(
1102→						parseResult.issues,
1103→						filteredContext.files,
1104→					);
1105→
1106→					// Convert Map to Record for serialization
1107→					const perFileIssuesRecord: Record<string, Issue[]> = {};
1108→					for (const [path, issues] of perFileIssues) {
1109→						perFileIssuesRecord[path] = issues;
1110→					}
1111→
1112→					// Always log evaluator completion with timing
1113→					const evalLogger = createLogger(evaluatorName);
1114→					evalLogger.log(`✓ Completed in ${evaluatorDuration.toFixed(1)}s`);
1115→
1116→					if (verbose) {
1117→						const evaluatorLogger = createLogger("Evaluator");
1118→						const totalPerFile = Array.from(perFileIssues.values()).reduce(
1119→							(sum, arr) => sum + arr.length,
1120→							0,
1121→						);
1122→						evaluatorLogger.log(
1123→							`Found ${totalPerFile} per-file issues and ${crossFileIssues.length} cross-file issues`,
1124→						);
1125→						if (errors.length > 0) {
1126→							evaluatorLogger.warn(
1127→								`⚠️  ${errors.length} parsing error(s) occurred`,
1128→							);
1129→						}
1130→						if (response.usage) {
1131→							evaluatorLogger.log(formatTokenUsage(response.usage));
1132→						}
1133→					}
1134→
1135→					return {
1136→						evaluator: evaluatorName,
1137→						perFileIssues: perFileIssuesRecord,
1138→						crossFileIssues,
1139→						errors: errors.length > 0 ? errors : undefined,
1140→						usage: response.usage,
1141→						cost_usd: response.cost_usd,
1142→						duration_ms: response.duration_ms,
1143→						finalPrompt: fullPrompt,
1144→					};
1145→				} catch (error) {
1146→					const errorMessage =
1147→						error instanceof Error ? error.message : String(error);
1148→					const isTimeout =
1149→						errorMessage.includes("timeout") ||
1150→						errorMessage.includes("TIMEOUT");
1151→
1152→					// Log with appropriate symbol and timing info
1153→					const evalLogger = createLogger(evaluatorName);
1154→					if (isTimeout) {
1155→						evalLogger.log(`❌ TIMEOUT after ${(timeout / 1000).toFixed(1)}s`);
1156→					} else if (verbose) {
1157→						unifiedLogger.error(
1158→							`Evaluator ${evaluatorName} failed: ${errorMessage}`,
1159→						);
1160→					}
1161→
1162→					// Create structured error
1163→					const structuredError: StructuredError = {
1164→						message: errorMessage,
1165→						category: determineErrorCategory(error),
1166→						severity: "partial",
1167→						evaluatorName: evaluatorName,
1168→						timestamp: new Date(),
1169→						retryable: false,
1170→						technicalDetails: error instanceof Error ? error.stack : undefined,
1171→					};
1172→
1173→					// Initialize empty per-file issues
1174→					const perFileIssues: Record<string, Issue[]> = {};
1175→					for (const file of context.files) {
1176→						perFileIssues[file.relativePath] = [];
1177→					}
1178→
1179→					return {
1180→						evaluator: evaluatorName,
1181→						perFileIssues,
1182→						crossFileIssues: [],
1183→						error: errorMessage,
1184→						errors: [structuredError],
1185→					};
1186→				}
1187→			},
1188→		);
1189→
1190→	// Aggregate results by file and collect cross-file issues
1191→	const fileResults: Record<string, FileEvaluationResult> = {};
1192→	const allCrossFileIssues: Issue[] = [];
1193→	let totalInputTokens = 0;
1194→	let totalOutputTokens = 0;
1195→	let totalCacheCreation = 0;
1196→	let totalCacheRead = 0;
1197→	let totalCost = 0;
1198→	let totalDuration = 0;
1199→
1200→	// Initialize file results
1201→	for (const file of context.files) {
1202→		const fileEvaluations: EvaluatorResult[] = [];
1203→
1204→		for (const evalResult of evaluatorResults) {
1205→			if (!evalResult?.perFileIssues) {
1206→				// Skip malformed results (e.g., raw Error from concurrency limiter)
1207→				continue;
1208→			}
1209→			const fileIssues = evalResult.perFileIssues[file.relativePath] || [];
1210→			fileEvaluations.push({
1211→				evaluator: evalResult.evaluator,
1212→				issues: fileIssues,
1213→				error: evalResult.error,
1214→				// Usage is shared across all files in unified mode, so we don't include per-file usage
1215→			});
1216→		}
1217→
1218→		fileResults[file.relativePath] = createFileResult(
1219→			file.filePath,
1220→			file.relativePath,
1221→			fileEvaluations,
1222→		);
1223→	}
1224→
1225→	// Aggregate cross-file issues and usage
1226→	for (const evalResult of evaluatorResults) {
1227→		if (!evalResult?.perFileIssues) {
1228→			// Skip malformed results (e.g., raw Error from concurrency limiter)
1229→			continue;
1230→		}
1231→		allCrossFileIssues.push(
1232→			...evalResult.crossFileIssues.map((issue) => ({
1233→				...issue,
1234→				evaluatorName: evalResult.evaluator,
1235→			})),
1236→		);
1237→
1238→		if (evalResult.usage) {
1239→			totalInputTokens += evalResult.usage.input_tokens;
1240→			totalOutputTokens += evalResult.usage.output_tokens;
1241→			totalCacheCreation += evalResult.usage.cache_creation_input_tokens || 0;
1242→			totalCacheRead += evalResult.usage.cache_read_input_tokens || 0;
1243→		}
1244→		if (evalResult.cost_usd) {
1245→			totalCost += evalResult.cost_usd;
1246→		}
1247→		if (evalResult.duration_ms) {
1248→			totalDuration += evalResult.duration_ms;
1249→		}
1250→	}
1251→
1252→	return {
1253→		files: fileResults,
1254→		crossFileIssues: allCrossFileIssues,
1255→		evaluatorResults,
1256→		totalUsage: {
1257→			input_tokens: totalInputTokens,
1258→			output_tokens: totalOutputTokens,
1259→			cache_creation_input_tokens: totalCacheCreation,
1260→			cache_read_input_tokens: totalCacheRead,
1261→		},
1262→		totalCost: totalCost > 0 ? totalCost : undefined,
1263→		totalDuration: totalDuration > 0 ? totalDuration : undefined,
1264→	};
1265→}
1266→

