  1→// Core evaluation type definitions
  2→// Consolidates types from frontend and CLI
  3→
  4→import type { ISkill } from "@shared/file-system/skills-finder";
  5→import type { ProviderName } from "@shared/providers/types";
  6→
  7→// Re-export ISkill for convenience
  8→export type { ISkill } from "@shared/file-system/skills-finder";
  9→
 10→// Evaluator filter type
 11→export type EvaluatorFilter = "all" | "errors" | "suggestions";
 12→
 13→// Error severity levels
 14→export type ErrorSeverity = "fatal" | "partial" | "warning";
 15→
 16→// Error categories
 17→export type ErrorCategory =
 18→	| "provider" // AI provider errors
 19→	| "parsing" // Response parsing failures
 20→	| "repository" // Git/repo access
 21→	| "file_system" // File operations
 22→	| "timeout" // Operation timeouts
 23→	| "internal"; // Unexpected errors
 24→
 25→export interface StructuredError {
 26→	message: string;
 27→	category: ErrorCategory;
 28→	severity: ErrorSeverity;
 29→	context?: Record<string, unknown>;
 30→	evaluatorName?: string;
 31→	filePath?: string;
 32→	timestamp: Date;
 33→	retryable: boolean;
 34→	technicalDetails?: string; // Stack trace or detailed error info
 35→}
 36→
 37→// Context Score types - New "Base + Setup Bonus - Issue Penalty" Algorithm
 38→export interface IContextScoreBreakdown {
 39→	// New algorithm components
 40→	baseScore: number; // Always 6.0 (supportive starting point)
 41→	setupBonus: {
 42→		agentsFilesBonus: number; // 0-2.0 based on number of AGENTS.md files
 43→		skillsBonus: number; // 0-0.75 based on skills count
 44→		linkedDocsBonus: number; // 0-0.75 based on linked docs count
 45→		total: number; // Sum of all setup bonuses (max 3.5)
 46→	};
 47→	issuePenalty: {
 48→		weightedIssueCount: number; // Raw weighted issue count before normalization
 49→		issueAllowance: number; // "Free" issues based on project size
 50→		excessIssues: number; // Issues beyond allowance
 51→		penalty: number; // Final penalty (0-3.0, soft cap)
 52→	};
 53→	context: {
 54→		projectSizeTier: "small" | "medium" | "large" | "enterprise";
 55→		totalLOC: number; // Lines of code from cloc
 56→		agentsFileCount: number;
 57→		skillsCount: number;
 58→		linkedDocsCount: number;
 59→		// Issue breakdown (3-level system: High 8-10, Medium 6-7, Low ≤5)
 60→		highIssues: number;
 61→		mediumIssues: number;
 62→		lowIssues: number;
 63→		errorCount: number;
 64→		suggestionCount: number;
 65→		// Documentation maturity metrics (optional for backward compatibility)
 66→		issuesPerFile?: number; // Total issues / AGENTS.md file count
 67→		documentationMaturityFactor?: number; // Penalty reduction factor (0.7-1.0)
 68→	};
 69→	// Legacy fields for backward compatibility
 70→	coveragePenalty?: number;
 71→	categoryDiversityPenalty?: number;
 72→	totalPenalty?: number;
 73→}
 74→
 75→export type ContextScoreGrade =
 76→	| "Excellent"
 77→	| "Good"
 78→	| "Fair"
 79→	| "Developing"
 80→	| "Getting Started";
 81→
 82→export interface IContextScore {
 83→	score: number;
 84→	grade: ContextScoreGrade;
 85→	summary: string;
 86→	breakdown: IContextScoreBreakdown;
 87→	recommendations: string[];
 88→	explanation: string; // User-friendly one-liner explaining the score
 89→}
 90→
 91→// Folder description for key folders analysis
 92→export interface IFolderDescription {
 93→	path: string; // Relative path (e.g., "src/components")
 94→	description: string; // Brief description (e.g., "React UI components")
 95→}
 96→
 97→/**
 98→ * Represents a context file (AGENTS.md, CLAUDE.md, .claude/rules/*.md, .cursor/rules/*.md/.mdc, copilot-instructions.md, or SKILL.md)
 99→ * with its content for browsing (no AI summarization needed)
100→ */
101→export interface IContextFile {
102→	/** Relative path from repository root */
103→	path: string;
104→	/** File type for categorization */
105→	type: "agents" | "claude" | "copilot" | "rules" | "cursor-rules" | "skills";
106→	/** Raw file content */
107→	content: string;
108→	/** Optional summary (unused - context files don't need AI summaries) */
109→	summary?: string;
110→	/** Globs from frontmatter (for rules files, UI display only) */
111→	globs?: string;
112→	/** Description from frontmatter (for cursor rules, UI display only) */
113→	description?: string;
114→	/** Whether the rule is always applied (for cursor rules) */
115→	alwaysApply?: boolean;
116→}
117→
118→/**
119→ * Represents a linked Markdown documentation file discovered in AGENTS.md
120→ */
121→export interface ILinkedDocSummary {
122→	/** Relative path from repository root */
123→	path: string;
124→	/** AI-generated 2-sentence summary */
125→	summary: string;
126→	/** Source AGENTS.md file that contains the link */
127→	linkedFrom: string;
128→	/** Raw file content for preview (optional for backward compatibility) */
129→	content?: string;
130→}
131→
132→// Technical inventory collected programmatically from the codebase
133→export interface ITechnicalInventory {
134→	dependencies?: string[];
135→	devDependencies?: string[];
136→	scripts?: Record<string, string>;
137→	dockerServices?: string[];
138→	fileCountsByExtension?: Record<string, number>;
139→	configFiles?: string[];
140→	envVarNames?: string[];
141→	// Database patterns (from evaluator 15 scanning)
142→	migrationFileCount?: number;
143→	ormRelationshipCount?: number;
144→	seedFileCount?: number;
145→	repositoryFileCount?: number;
146→	// Testing patterns (from evaluator 14 scanning)
147→	mockUsageCount?: number;
148→	fixtureDirectories?: string[];
149→	testUtilityFiles?: string[];
150→	testOrganization?: "co-located" | "separate" | "mixed";
151→	// Architecture patterns (from evaluator 12 scanning)
152→	detectedDirectoryLayers?: string[];
153→	// Gitignore entries (for fresh-clone context awareness)
154→	gitignoreEntries?: string[];
155→}
156→
157→// Project context types
158→export interface IProjectContext {
159→	languages: string;
160→	frameworks: string;
161→	architecture: string;
162→	patterns: string;
163→	raw: string; // Full text for prompt injection
164→	clocSummary?: string; // Formatted lines of code per language
165→	keyFolders?: IFolderDescription[]; // ~20 most important folders
166→	agentsFilePaths?: string[]; // Paths to all context files (AGENTS.md and CLAUDE.md)
167→	contextFiles?: IContextFile[]; // Context files with content and summaries for browsing
168→	skills?: ISkill[]; // Agent Skills cartography (from SKILL.md files)
169→	linkedDocs?: ILinkedDocSummary[]; // AI-summarized documentation linked from AGENTS.md
170→	technicalInventory?: ITechnicalInventory; // Pre-computed technical data from codebase
171→	colocatedPairs?: Array<{
172→		directory: string;
173→		agentsPath: string;
174→		claudePath: string;
175→	}>; // Directories where both AGENTS.md and CLAUDE.md coexist with different content
176→}
177→
178→export interface IContextIdentifierResult {
179→	context: IProjectContext;
180→	clocAvailable: boolean;
181→	clocOutput?: string;
182→	usage?: Usage;
183→	cost_usd?: number;
184→	duration_ms?: number;
185→}
186→
187→export interface IContextIdentifierOptions {
188→	verbose?: boolean;
189→	timeout?: number;
190→	clocTimeout?: number;
191→	agentsFilePaths?: string[]; // Discovered context file paths (AGENTS.md / CLAUDE.md) to include in context
192→	/** AI provider to use (defaults to claude) */
193→	provider?: ProviderName;
194→	/** Progress callback for emitting context sub-step events */
195→	progressCallback?: ProgressCallback;
196→}
197→
198→// Curation types
199→export interface ICuratedIssue {
200→	originalIndex: number;
201→	reason: string;
202→}
203→
204→export interface ICurationSummary {
205→	totalIssuesReviewed: number;
206→}
207→
208→export interface ICurationResult {
209→	curatedIssues: ICuratedIssue[];
210→	totalIssuesReviewed: number;
211→	usage?: Usage;
212→	cost_usd?: number;
213→	duration_ms?: number;
214→}
215→
216→export interface ICurationOutput {
217→	// New dual format
218→	errors?: {
219→		curatedIssues: (Issue & { curationReason: string })[];
220→		summary: ICurationSummary;
221→	};
222→	suggestions?: {
223→		curatedIssues: (Issue & { curationReason: string })[];
224→		summary: ICurationSummary;
225→	};
226→	// Legacy fields (backward compatibility)
227→	curatedIssues?: (Issue & { curationReason: string })[];
228→	summary?: ICurationSummary;
229→}
230→
231→export interface ICurationOptions {
232→	enabled?: boolean;
233→	errorTopN?: number; // New: threshold for errors (default 20)
234→	suggestionTopN?: number; // New: threshold for suggestions (default 20)
235→	topN?: number; // Deprecated (backward compatibility)
236→}
237→
238→/**
239→ * Deduplication options (Phase 1: rule-based + Phase 2: AI semantic + Phase 3: entity clustering)
240→ */
241→export interface IDeduplicationOptions {
242→	/** Enable deduplication (default: true) */
243→	enabled?: boolean;
244→	/** Location overlap tolerance in lines (default: 5) */
245→	locationTolerance?: number;
246→	/** Text similarity threshold 0-1 (default: 0.55) */
247→	similarityThreshold?: number;
248→	/** Enable AI semantic deduplication (Phase 2, default: true) */
249→	aiEnabled?: boolean;
250→	/** Maximum issues to send to AI (default: 500, token limit safety) */
251→	maxIssuesForAI?: number;
252→}
253→
254→export interface Location {
255→	file?: string;
256→	start: number;
257→	end: number;
258→}
259→
260→export interface SnippetInfo {
261→	content: string; // Full snippet with context lines
262→	startLine: number; // First line number of snippet (1-indexed)
263→	highlightStart: number; // Line number where highlight starts (1-indexed)
264→	highlightEnd: number; // Line number where highlight ends (1-indexed)
265→	file?: string; // File path for cross-file snippets
266→}
267→
268→// Metadata for clustered issues (Phase 3 entity-based deduplication)
269→export interface ClusteredIssueMetadata {
270→	category: string;
271→	evaluatorName?: string;
272→	problem?: string;
273→	severity?: number;
274→	impactLevel?: "High" | "Medium" | "Low";
275→	issueType: "error" | "suggestion";
276→}
277→
278→// Common fields shared by both error and suggestion issues
279→interface BaseIssue {
280→	category: string;
281→	problem?: string;
282→	description?: string;
283→	title?: string;
284→	location: Location | Location[];
285→	impact?: string; // Explanation text (why it matters)
286→	fix?: string;
287→	recommendation?: string;
288→	suggestion?: string;
289→	affectedFiles?: string[];
290→	isMultiFile?: boolean;
291→	context?: string;
292→	quote?: string;
293→	pattern?: string;
294→	issue?: string;
295→	snippet?: string; // Actual content at the location (extracted from file)
296→	snippetInfo?: SnippetInfo; // Snippet with context and line number metadata
297→	snippets?: SnippetInfo[]; // Multiple snippets for cross-file issues
298→	snippetError?: string; // Reason why snippet is not available (e.g., "File not found", "Line exceeds file length")
299→	isPhantomFile?: boolean; // Indicates this references a suggested file location that doesn't exist yet (e.g., subdirectory AGENTS.md)
300→	evaluatorName?: string; // Name of the evaluator that found this issue
301→	issueType: "error" | "suggestion"; // Whether this is an error (problem to fix) or suggestion (opportunity to improve)
302→	_deduplicationId?: string; // Internal tracking ID for deduplication
303→	validationWarnings?: string[]; // Warnings about potential false positives (e.g., hallucinated pronouns)
304→	// Phase 3 entity-based deduplication metadata (optional, only present on clustered issues)
305→	clusteredEntity?: string; // The entity (command, term, file) that all issues reference
306→	clusteredCount?: number; // Total number of issues clustered together
307→	clusteredIssues?: ClusteredIssueMetadata[]; // Metadata for all issues in the cluster
308→}
309→
310→// Error issues have severity only
311→export interface ErrorIssue extends BaseIssue {
312→	issueType: "error";
313→	severity: number; // 6-10 scale
314→	impactLevel?: never; // Explicitly forbidden
315→}
316→
317→// Suggestion issues have impactLevel only
318→export interface SuggestionIssue extends BaseIssue {
319→	issueType: "suggestion";
320→	impactLevel: "High" | "Medium" | "Low"; // Impact level for suggestions
321→	severity?: never; // Explicitly forbidden
322→}
323→
324→// Union type for all issues
325→export type Issue = ErrorIssue | SuggestionIssue;
326→
327→export interface Usage {
328→	input_tokens: number;
329→	output_tokens: number;
330→	cache_creation_input_tokens: number;
331→	cache_read_input_tokens: number;
