525→	/** AI provider to use (defaults to 'claude') */
526→	provider?: ProviderName;
527→	/**
528→	 * Preserve debug output files after successful evaluation
529→	 * Default: false (debug output is cleaned up on success)
530→	 * Set to true to keep debug files for inspection
531→	 */
532→	preserveDebugOutput?: boolean;
533→	/**
534→	 * Filter evaluators by type
535→	 * - "all": Run all evaluators (default)
536→	 * - "errors": Run only error evaluators (issues in existing content)
537→	 * - "suggestions": Run only suggestion evaluators (improvement opportunities)
538→	 */
539→	evaluatorFilter?: EvaluatorFilter;
540→	/**
541→	 * Specific evaluator IDs to run (filenames without .md extension).
542→	 * When set and non-empty, overrides evaluatorFilter.
543→	 * Example: ["content-quality", "security", "context-gaps"]
544→	 */
545→	selectedEvaluators?: string[];
546→	/**
547→	 * Enable assessment features (feedback buttons, selection basket, assessment page)
548→	 * - Default: false (features hidden)
549→	 * - Set to true to enable like/dislike buttons, issue selection, and assessment page
550→	 */
551→	enableAssessmentFeatures?: boolean;
552→	/**
553→	 * Number of parallel AI calls for linked documentation summarization
554→	 * - Default: 3
555→	 * - Range: 1-10
556→	 * - Higher values speed up summarization but may hit rate limits
557→	 */
558→	linkedDocsConcurrency?: number;
559→	/**
560→	 * Evaluation timeout in milliseconds per evaluator
561→	 * - Default: 300000 (5 minutes)
562→	 */
563→	timeout?: number;
564→	/** Whether running in cloud mode (enforces repo size limits) */
565→	cloudMode?: boolean;
566→}
567→
568→export interface IEvaluationRequest {
569→	repositoryUrl?: string;
570→	localPath?: string;
571→	options?: IEvaluationOptions;
572→}
573→
574→export interface ProgressEvent {
575→	type:
576→		| "job.queued"
577→		| "file.started"
578→		| "file.completed"
579→		| "evaluator.progress"
580→		| "evaluator.completed"
581→		| "evaluator.retry"
582→		| "evaluator.timeout"
583→		| "job.started"
584→		| "job.completed"
585→		| "job.failed"
586→		| "curation.started"
587→		| "curation.completed"
588→		| "context.started"
589→		| "context.completed"
590→		| "evaluation.warning"
591→		// Clone events
592→		| "clone.started"
593→		| "clone.completed"
594→		| "clone.warning"
595→		// Discovery events
596→		| "discovery.started"
597→		| "discovery.completed"
598→		// Context sub-step events
599→		| "context.cloc"
600→		| "context.folders"
601→		| "context.analysis"
602→		| "context.warning";
603→	data: unknown;
604→}
605→
606→export type ProgressCallback = (event: ProgressEvent) => void;
607→
608→// Type guard for StructuredError
609→export function isStructuredError(error: unknown): error is StructuredError {
610→	return (
611→		typeof error === "object" &&
612→		error !== null &&
613→		"message" in error &&
614→		"category" in error &&
615→		"severity" in error &&
616→		"timestamp" in error &&
617→		"retryable" in error
618→	);
619→}
620→
621→// Convert impact level to numeric severity for sorting
622→// High: 7-10, Medium: 5-6, Low: 1-4
623→export function impactToSeverity(
624→	impactLevel: "High" | "Medium" | "Low",
625→): number {
626→	if (impactLevel === "High") return 9;
627→	if (impactLevel === "Medium") return 6;
628→	return 3;
629→}
630→
631→// Helper to get sortable severity value from any issue
632→export function getIssueSeverity(issue: Issue): number {
633→	if (issue.issueType === "error") {
634→		return issue.severity;
635→	}
636→	return impactToSeverity(issue.impactLevel);
637→}
